{
  "componentArchitecture": {
    "corePrinciples": {
      "evidenceFirst": "All data and insights must be presented with clear provenance, source, and validation status. Evidence is the foundation of all decisions and must be traceable and auditable.",
      "transparentReasoning": "All reasoning, assumptions, and logic must be visible, explainable, and modifiable. Users must understand how decisions are reached and be able to challenge or refine them.",
      "userControl": "Users must have full control over their data, insights, and the narrative they build. This includes the ability to filter, annotate, and share evidence.",
      "riskAwareness": "All interactions must include risk indicators, scenario analysis, and mitigation strategies. Users must be aware of the potential consequences of their decisions.",
      "calmPrecision": "The interface must be intuitive, uncluttered, and focused on clarity. It must support deep analysis without overwhelming the user with noise."
    },
    "componentContracts": {
      "evidenceCard": {
        "purpose": "Display a single piece of market evidence with metadata, source, validation status, and contextual annotations.",
        "props": {
          "evidenceId": "string",
          "source": "string",
          "timestamp": "datetime",
          "validationStatus": "string (pending, approved, rejected)",
          "confidenceScore": "number (0-1)",
          "annotations": "array of strings",
          "tags": "array of strings"
        },
        "events": {
          "validateEvidence": "triggered when user confirms evidence is valid",
          "rejectEvidence": "triggered when user rejects evidence",
          "addAnnotation": "triggered when user adds a note to the evidence"
        }
      },
      "riskIndicator": {
        "purpose": "Display risk level and mitigation options for a given decision or insight.",
        "props": {
          "riskLevel": "string (low, medium, high)",
          "scenarioAnalysis": "array of strings",
          "mitigationOptions": "array of strings",
          "impactScore": "number (0-1)"
        },
        "events": {
          "viewScenario": "triggered when user wants to explore a specific risk scenario",
          "selectMitigation": "triggered when user selects a mitigation strategy"
        }
      },
      "timelineNarrative": {
        "purpose": "Visualize the evolution of a decision over time, showing how evidence was filtered, challenged, and approved.",
        "props": {
          "timelineId": "string",
          "events": "array of objects with timestamp, action, and evidenceId",
          "userAnnotations": "array of strings",
          "finalDecision": "object with decision, rationale, and risk indicators"
        },
        "events": {
          "addAnnotation": "triggered when user adds a note to the timeline",
          "viewDecisionRationale": "triggered when user wants to explore the final decision rationale"
        }
      },
      "annotationPanel": {
        "purpose": "Allow users to add, edit, and manage annotations on evidence or timelines.",
        "props": {
          "currentFocus": "string (evidenceId or timelineId)",
          "annotations": "array of strings",
          "annotationMode": "boolean"
        },
        "events": {
          "saveAnnotation": "triggered when user saves a new annotation",
          "deleteAnnotation": "triggered when user deletes an existing annotation"
        }
      },
      "validationPanel": {
        "purpose": "Allow users to review, validate, or reject evidence with reasoning and justification.",
        "props": {
          "evidenceId": "string",
          "validationStatus": "string",
          "reasoning": "string",
          "justification": "string"
        },
        "events": {
          "submitValidation": "triggered when user submits a validation decision",
          "addReasoning": "triggered when user adds reasoning for validation"
        }
      },
      "riskDashboard": {
        "purpose": "Aggregate and display risk indicators across all active decisions and evidence.",
        "props": {
          "activeRisks": "array of objects with riskId, riskLevel, impactScore, and mitigationOptions",
          "userPreferences": "object with riskThresholds and mitigationPriorities"
        },
        "events": {
          "filterByRiskLevel": "triggered when user filters risks by level",
          "sortByImpact": "triggered when user sorts risks by impact"
        }
      },
      "decisionSummary": {
        "purpose": "Provide a concise summary of a final decision, including evidence, reasoning, and risk indicators.",
        "props": {
          "decisionId": "string",
          "evidenceList": "array of evidenceIds",
          "reasoning": "string",
          "riskIndicators": "array of risk indicators",
          "finalRationale": "string"
        },
        "events": {
          "viewFullRationale": "triggered when user wants to see the full rationale"
        }
      }
    },
    "tokenSystem": {
      "colorTokens": {
        "primary": "#1E3A8A",
        "secondary": "#6366F1",
        "success": "#10B981",
        "warning": "#F59E0B",
        "danger": "#EF4444",
        "neutral": "#9CA3AF"
      },
      "spacingTokens": {
        "xs": "0.25rem",
        "sm": "0.5rem",
        "md": "1rem",
        "lg": "2rem",
        "xl": "4rem"
      },
